parameters.jsCode:
const body = $json.body || $json;
const sqft = parseInt(body.square_feet) || 1000;
const bedrooms = parseInt(body.bedrooms) || 2;
const bathrooms = parseInt(body.bathrooms) || 1;
const service = body.service_type || 'standard';
const extras = body.extras || [];

// Pricing logic
let basePrice = sqft * 0.15;
basePrice += bedrooms * 25;
basePrice += bathrooms * 35;

if (service === 'deep_clean') basePrice *= 1.5;
if (service === 'move_in_out') basePrice *= 2.0;

let extraCost = 0;
if (extras.includes('windows')) extraCost += 75;
if (extras.includes('carpet')) extraCost += 120;
if (extras.includes('fridge')) extraCost += 45;
if (extras.includes('oven')) extraCost += 45;

const total = Math.round(basePrice + extraCost);
const duration = Math.ceil((sqft / 500) + (bedrooms * 0.5) + (bathrooms * 0.5)) + ' hours';

return [{
  json: {
    customer_name: body.customer_name || '',
    customer_phone: body.customer_phone || '',
    customer_email: body.customer_email || '',
    address: body.address || '',
    square_feet: sqft,
    bedrooms: bedrooms,
    bathrooms: bathrooms,
    service_type: service,
    extras: extras,
    base_price: Math.round(basePrice),
    extra_cost: extraCost,
    total_price: total,
    estimated_duration: duration,
    quote_id: 'QTE-' + Date.now().toString(36).toUpperCase()
  }
}];

